// MARK: - Cloud API Service

class CloudAPIService {
    
    private let client: HTTPClient
    
    init(client: HTTPClient = .shared) {
        self.client = client
    }
    
    // MARK: - Models
    
    struct DeviceRegistration: Codable {
        let deviceId: String
        let name: String
        let type: String
        let firmwareVersion: String
    }
    
    struct DeviceListResponse: Codable {
        let devices: [DeviceRegistration]
        let totalCount: Int
    }
    
    struct AuthResponse: Codable {
        let token: String
        let expiresIn: Int
        let refreshToken: String
    }
    
    struct LoginRequest: Codable {
        let email: String
        let password: String
    }
    
    struct APIMessage: Codable {
        let message: String
        let success: Bool
    }
    
    // MARK: - Authentication
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let loginRequest = LoginRequest(email: email, password: password)
        let response = try await client.request(
            url: "\(client.cloudBaseURL)/auth/login",
            method: .POST,
            body: loginRequest,
            configuration: .cloudAPI,
            responseType: AuthResponse.self
        )
        // Store the token for subsequent requests
        client.authToken = response.data.token
        return response.data
    }
    
    // MARK: - Device Management
    
    func getRegisteredDevices() async throws -> DeviceListResponse {
        let response = try await client.request(
            url: "\(client.cloudBaseURL)/devices",
            method: .GET,
            body: nil as String?,
            configuration: .cloudAPI,
            responseType: DeviceListResponse.self
        )
        return response.data
    }
    
    func registerDevice(_ device: DeviceRegistration) async throws -> APIMessage {
        let response = try await client.request(
            url: "\(client.cloudBaseURL)/devices",
            method: .POST,
            body: device,
            configuration: .cloudAPI,
            responseType: APIMessage.self
        )
        return response.data
    }
    
    func deleteDevice(deviceId: String) async throws -> APIMessage {
        let response = try await client.request(
            url: "\(client.cloudBaseURL)/devices/\(deviceId)",
            method: .DELETE,
            body: nil as String?,
            configuration: .cloudAPI,
            responseType: APIMessage.self
        )
        return response.data
    }
}

